+async function benchmarkCypherQueries(
+  hypergraph: any,
+  queryTypes: string[]
+): Promise<any> {
+  const queryResults: any = {};
+
+  for (const queryType of queryTypes) {
+    const start = Date.now();
+    const result = await executeCypherQuery(hypergraph, queryType);
