+
+function buildBaseline(graph: any, M: number): void {
+  for (let i = 0; i < graph.vectors.length; i++) {
+    const neighbors = findNearestNeighbors(graph.vectors, i, M);
+    graph.edges.set(i, neighbors);
+  }
