+}
+
+function analyzeAttentionGuidance(results: any[]): any {
+  const attentionResults = results.filter(r => r.strategy === 'attention-guided');
+
+  if (attentionResults.length === 0) {
+    return { efficiency: 0, pathPruning: 0 };
